package jsrt

import (
	"context"
	"errors"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"sync"

	"github.com/fastschema/qjs"
	pluginapi "github.com/vaayne/anna/pkg/plugin"
)

// JSPlugin wraps a single JS extension loaded via QJS.
// All JS calls are serialized via mu since QJS runtimes are not goroutine-safe.
type JSPlugin struct {
	name    string
	mu      sync.Mutex
	runtime *qjs.Runtime
}

func (p *JSPlugin) Name() string  { return p.name }
func (p *JSPlugin) Init(_ pluginapi.Context) error { return nil }

func (p *JSPlugin) Close() error {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.runtime != nil {
		p.runtime.Close()
		p.runtime = nil
	}
	return nil
}

// LoadJS loads a JS extension from the given path, registers its tools and hooks
// into the registry, and returns a JSPlugin that satisfies pluginapi.Plugin.
func LoadJS(path string, cfg map[string]any, registry toolHookRegistrar, logger *slog.Logger) (*JSPlugin, error) {
	code, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("read plugin file: %w", err)
	}

	pluginName := pluginNameFromPath(path)
	pluginDir := filepath.Dir(path)
	plog := logger.With("plugin", pluginName)

	rt, err := qjs.New()
	if err != nil {
		return nil, fmt.Errorf("create qjs runtime: %w", err)
	}

	ctx := rt.Context()

	// Build the anna host object passed to the default export function.
	anna := ctx.NewObject()

	// anna.config — read-only config from YAML.
	configVal, err := goMapToJSValue(ctx, cfg)
	if err != nil {
		rt.Close()
		return nil, fmt.Errorf("convert config to JS: %w", err)
	}
	anna.SetPropertyStr("config", configVal)

	// Host APIs.
	ha := &hostAPI{
		logger:    plog,
		pluginDir: pluginDir,
	}
	registerHostAPIs(ctx, anna, ha)

	// Collectors for tools and hooks registered during init.
	var tools []pluginapi.Tool
	var hooks []hookEntry

	// anna.registerTool({ name, description, parameters, execute })
	ctx.Global().SetPropertyStr("__anna_registerTool", ctx.NewGoFunc("__anna_registerTool", func(this *qjs.This) (*qjs.Value, error) {
		t, executeFn, err := parseToolDef(this)
		if err != nil {
			return nil, err
		}
		// Wrap the JS execute function so it can be called from Go.
		t.Execute = makeToolExecutor(rt, executeFn, &JSPlugin{name: pluginName})
		tools = append(tools, t)
		return this.Context().NewBool(true), nil
	}))

	// anna.on(event, handler)
	ctx.Global().SetPropertyStr("__anna_on", ctx.NewGoFunc("__anna_on", func(this *qjs.This) (*qjs.Value, error) {
		args := this.Args()
		if len(args) < 2 {
			return nil, errors.New("anna.on requires (event, handler)")
		}
		eventName := args[0].String()
		handlerFn := args[1].Clone()
		hooks = append(hooks, hookEntry{
			event:   pluginapi.EventKind(eventName),
			handler: handlerFn,
		})
		return this.Context().NewBool(true), nil
	}))

	// JS shim: wrap __anna_registerTool and __anna_on into anna object methods.
	shimCode := `
		(function(anna) {
			anna.registerTool = function(def) { return __anna_registerTool(def); };
			anna.on = function(event, handler) { return __anna_on(event, handler); };
			return anna;
		})
	`
	shimFn, err := ctx.Eval("shim.js", qjs.Code(shimCode))
	if err != nil {
		rt.Close()
		return nil, fmt.Errorf("eval shim: %w", err)
	}
	defer shimFn.Free()

	annaReady, err := shimFn.InvokeJS("call", anna)
	if err != nil {
		rt.Close()
		return nil, fmt.Errorf("invoke shim: %w", err)
	}
	defer annaReady.Free()

	// Load the plugin module. The default export should be a function(anna).
	// We wrap it so it's callable as a regular script.
	wrappedCode := fmt.Sprintf(
		"(function() {\n"+
			"  const __mod = (function(anna) {\n%s\n});\n"+
			"  __mod(__anna_obj);\n"+
			"})();\n",
		string(code),
	)
	ctx.Global().SetPropertyStr("__anna_obj", annaReady.Clone())

	_, err = ctx.Eval(filepath.Base(path), qjs.Code(wrappedCode))
	if err != nil {
		rt.Close()
		return nil, fmt.Errorf("eval plugin %s: %w", pluginName, err)
	}

	plugin := &JSPlugin{
		name:    pluginName,
		runtime: rt,
	}

	// Register collected tools into the registry.
	for _, t := range tools {
		// Rebind the executor to the real plugin (for mutex).
		t.Execute = makeToolExecutor(rt, findToolHandler(ctx, t.Name, tools), plugin)
		if err := registry.RegisterTool(t); err != nil {
			plog.Warn("failed to register tool", "tool", t.Name, "error", err)
		}
	}

	// Register collected hooks into the registry.
	for _, h := range hooks {
		fn := makeHookFunc(rt, h.handler, plugin, plog)
		registry.RegisterHook(h.event, fn)
	}

	plog.Info("JS plugin loaded", "tools", len(tools), "hooks", len(hooks))
	return plugin, nil
}

// toolHookRegistrar is the subset of Registry that LoadJS needs.
type toolHookRegistrar interface {
	RegisterTool(pluginapi.Tool) error
	RegisterHook(pluginapi.EventKind, pluginapi.HookFunc)
}

type hookEntry struct {
	event   pluginapi.EventKind
	handler *qjs.Value
}

// parseToolDef extracts tool metadata from the JS object argument.
func parseToolDef(this *qjs.This) (pluginapi.Tool, *qjs.Value, error) {
	args := this.Args()
	if len(args) < 1 {
		return pluginapi.Tool{}, nil, errors.New("registerTool requires a tool definition object")
	}
	def := args[0]

	name := def.GetPropertyStr("name")
	if name.IsUndefined() || name.String() == "" {
		return pluginapi.Tool{}, nil, errors.New("tool name is required")
	}

	desc := def.GetPropertyStr("description")
	executeFn := def.GetPropertyStr("execute")
	if executeFn.IsUndefined() || !executeFn.IsFunction() {
		return pluginapi.Tool{}, nil, fmt.Errorf("tool %q requires an execute function", name.String())
	}

	// Parse parameters/inputSchema as a Go map.
	params := def.GetPropertyStr("parameters")
	var inputSchema map[string]any
	if !params.IsUndefined() && !params.IsNull() {
		inputSchema = jsValueToGoMap(params)
	}

	t := pluginapi.Tool{
		Name:        name.String(),
		Description: desc.String(),
		InputSchema: inputSchema,
	}

	return t, executeFn.Clone(), nil
}

// makeToolExecutor creates a Go function that calls the JS execute function,
// serialized by the plugin's mutex.
func makeToolExecutor(rt *qjs.Runtime, executeFn *qjs.Value, p *JSPlugin) func(context.Context, map[string]any) (string, error) {
	return func(_ context.Context, args map[string]any) (string, error) {
		p.mu.Lock()
		defer p.mu.Unlock()
		if p.runtime == nil {
			return "", errors.New("plugin is closed")
		}

		ctx := rt.Context()
		argsVal, err := goMapToJSValue(ctx, args)
		if err != nil {
			return "", fmt.Errorf("convert args to JS: %w", err)
		}

		result, err := executeFn.InvokeJS("call", ctx.NewNull(), argsVal)
		if err != nil {
			return "", fmt.Errorf("tool execute error: %w", err)
		}
		defer result.Free()

		return result.String(), nil
	}
}

// makeHookFunc creates a pluginapi.HookFunc that calls the JS handler,
// serialized by the plugin's mutex.
func makeHookFunc(rt *qjs.Runtime, handler *qjs.Value, p *JSPlugin, logger *slog.Logger) pluginapi.HookFunc {
	return func(_ context.Context, event any) error {
		p.mu.Lock()
		defer p.mu.Unlock()
		if p.runtime == nil {
			return nil
		}

		ctx := rt.Context()
		eventVal, err := goToJSValue(ctx, event)
		if err != nil {
			logger.Warn("failed to convert hook event to JS", "error", err)
			return nil
		}

		result, err := handler.InvokeJS("call", ctx.NewNull(), eventVal)
		if err != nil {
			logger.Warn("hook handler error", "error", err)
			return nil
		}
		defer result.Free()

		// Hook cancellation: if the handler returns a non-empty string, block the action.
		if result.IsString() {
			reason := result.String()
			if reason != "" && reason != "undefined" {
				return errors.New(reason)
			}
		}
		return nil
	}
}

