// registerHostAPIs sets log, readFile, writeFile, and fetch on the anna object.
func registerHostAPIs(ctx *qjs.Context, anna *qjs.Value, ha *hostAPI) {
	// anna.log(level, msg)
	anna.SetPropertyStr("log", ctx.NewGoFunc("log", func(this *qjs.This) (*qjs.Value, error) {
		args := this.Args()
		if len(args) < 2 {
			return nil, errors.New("anna.log requires (level, msg)")
		}
		level := args[0].String()
		msg := args[1].String()
		switch strings.ToLower(level) {
		case "debug":
			ha.logger.Debug(msg)
		case "warn", "warning":
			ha.logger.Warn(msg)
		case "error":
			ha.logger.Error(msg)
