  const imageXml = siteConfig.ogImage
    ? `\n    <image>\n      <url>${escapeXml(baseUrl + siteConfig.ogImage)}</url>\n      <title>${escapeXml(siteTitle)}</title>\n      <link>${escapeXml(baseUrl)}</link>\n    </image>`
    : '';

  const rssItemsXml = items
    .map((item) => {
