describe("setupCommands", () => {
  it("creates all command files", async () => {
    await setupCommands(gitRoot);

    for (const filename of Object.keys(BRAIN_COMMANDS)) {
      expect(existsSync(join(gitRoot, ".claude", "commands", filename))).toBe(true);
